const input = $input.first().json;
const body = input.body || input;

const url = (body.url || '').trim();
if (!url) throw new Error('url is required');

// Basic URL validation — only allow http/https
if (!/^https?:\/\//i.test(url)) throw new Error('Invalid URL: must start with http:// or https://');

// Detect platform
let platform = 'other';
if (/youtube\.com|youtu\.be/i.test(url)) platform = 'youtube';
else if (/tiktok\.com/i.test(url)) platform = 'tiktok';
else if (/instagram\.com/i.test(url)) platform = 'instagram';

return [{ json: {
  url,
  platform,
  analysis_focus: body.analysis_focus || '',
  reference_id: body.reference_id || null
}}];

const rows = $('⚙️ Настройки AI').all().map(i => i.json);
const settings = {};
for (const r of rows) { if (r.key) settings[r.key] = r.value; }
const params = $('🔍 Валидация входа').first().json;
return [{ json: {
  ...params,
  ai_base_url: settings.ai_base_url || 'https://gptunnel.ru/v1',
  ai_model: settings.ai_model || 'gpt-4o'
}}];

const ctx = $input.first().json;
// Sanitize URL — escape single quotes to prevent command injection
const safeUrl = ctx.url.replace(/'/g, "'\\''");
// Run yt-dlp: dump JSON metadata only (no download), timeout 60s
const cmd = [
  'set -e',
  `yt-dlp -j --no-playlist --socket-timeout 60 --no-warnings '${safeUrl}' 2>&1 | head -c 80000`
].join('\n');
return [{ json: { command: cmd, ctx } }];

const result = $input.first().json;
const ctx = $('🛠️ Команда yt-dlp').first().json.ctx;

const stdout = (result.stdout || result.output || '').trim();
if (!stdout || stdout.startsWith('ERROR')) {
  throw new Error('yt-dlp failed: ' + (stdout || result.stderr || 'no output').substring(0, 300));
}

let meta;
try {
  // Take first complete JSON object (playlist returns multiple lines)
  const firstLine = stdout.split('\n').find(l => l.trim().startsWith('{'));
  meta = JSON.parse(firstLine || stdout);
} catch (e) {
  throw new Error('Failed to parse yt-dlp output: ' + e.message);
}

const tags = (meta.tags || []).slice(0, 20);
const description = (meta.description || '').substring(0, 600);

return [{ json: {
  ...ctx,
  meta_title: meta.title || '',
  meta_description: description,
  meta_view_count: meta.view_count || 0,
  meta_like_count: meta.like_count || 0,
  meta_duration: Math.round(meta.duration || 0),
  meta_tags: tags,
  meta_channel: meta.uploader || meta.channel || '',
  meta_upload_date: meta.upload_date || '',
  meta_thumbnail: meta.thumbnail || '',
  meta_extractor: meta.extractor || ctx.platform
}}];

const ctx = $input.first().json;

const systemPrompt = 'Ты — эксперт по вирусному видеоконтенту и контент-маркетингу для маркетплейсов (Wildberries, Ozon) и соцсетей (TikTok, Reels, Shorts).

Твоя задача: разобрать видео по косточкам и выявить точные триггеры вирусности.

Правила:
- Только достоверные наблюдения, не выдумывай факты.
- Анализируй структуру, хук, монтаж и психологические триггеры.
- Давай конкретные советы по адаптации для продуктового контента.

Отвечай СТРОГО в JSON.';

const durationMin = Math.floor(ctx.meta_duration / 60);
const durationSec = ctx.meta_duration % 60;
const durationStr = durationMin > 0 ? `${durationMin}м ${durationSec}с` : `${durationSec}с`;

const userMsg = `Проанализируй это видео:

Платформа: ${ctx.platform}
Название: ${ctx.meta_title}
Просмотры: ${(ctx.meta_view_count || 0).toLocaleString('ru')}
Лайки: ${(ctx.meta_like_count || 0).toLocaleString('ru')}
Длительность: ${durationStr}
Канал / автор: ${ctx.meta_channel}
Теги (до 15): ${(ctx.meta_tags || []).slice(0,15).join(', ') || 'нет'}
Описание (до 600 символов):
${ctx.meta_description}

${ctx.analysis_focus ? 'Фокус анализа: ' + ctx.analysis_focus + '

' : ''}Верни JSON строго такой структуры:
{
  "hook_type": "тип хука первых 2-3 сек: вопрос / шоковый-факт / обещание-результата / загадка / провокация / юмор",
  "video_structure": "краткое описание структуры видео (2-3 предложения)",
  "editing_style": "быстрый-монтаж / медленный / динамичный / POV / лайфстайл / продуктовый / talking-head",
  "viral_reasons": ["причина 1", "причина 2", "причина 3"],
  "viral_score": 8,
  "key_techniques": ["техника 1", "техника 2", "техника 3"],
  "adaptation_tips": ["конкретный совет 1 для продуктового видео", "совет 2", "совет 3"],
  "recommended_hooks": ["готовый хук 1", "готовый хук 2"]
}`;

return [{ json: {
  url: ctx.ai_base_url + '/chat/completions',
  body: JSON.stringify({
    model: ctx.ai_model,
    temperature: 0.5,
    max_tokens: 2000,
    response_format: { type: 'json_object' },
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: userMsg }
    ]
  }),
  ctx
}}];

const response = $input.first().json;
const ctx = $('🏗️ Промпт анализа').first().json.ctx;

let analysis;
try {
  const content = (response.body || response).choices[0].message.content;
  analysis = JSON.parse(content);
} catch (e) {
  throw new Error('Failed to parse LLM analysis: ' + e.message);
}

return [{ json: {
  ctx,
  analysis,
  viral_score: Math.min(10, Math.max(0, parseInt(analysis.viral_score) || 0)),
  hook_type: (analysis.hook_type || '').substring(0, 200),
  editing_style: (analysis.editing_style || '').substring(0, 200)
}}];

const saved = $('💾 Сохранить референс').first().json;
const ctx = $('📋 Парсинг анализа').first().json.ctx;
const analysis = $('📋 Парсинг анализа').first().json.analysis;
return [{ json: {
  success: true,
  reference_id: saved.id,
  url: ctx.url,
  platform: ctx.platform,
  title: ctx.meta_title,
  viral_score: saved.viral_score,
  hook_type: saved.hook_type,
  analysis
}}];
